import numpy as np
import time
import ctypes

# The C approach is consistently faster! Let me also try with SIMD optimizations
# Let me try with -O3 -march=native which should auto-vectorize

# Also, let me try with manual SIMD (AVX2)
c_code_avx = '''
#include <stdlib.h>
#include <immintrin.h>

void outer_product_avx(const double* vec1, const double* vec2, double* result, int n, int m) {
    for (int i = 0; i < n; i++) {
        double vi = vec1[i];
        __m256d vi_vec = _mm256_set1_pd(vi);
        int j = 0;
        for (; j + 3 < m; j += 4) {
            __m256d vj_vec = _mm256_loadu_pd(&vec2[j]);
            __m256d res = _mm256_mul_pd(vi_vec, vj_vec);
            _mm256_storeu_pd(&result[i * m + j], res);
        }
        for (; j < m; j++) {
            result[i * m + j] = vi * vec2[j];
        }
    }
}
'''

with open('/app/outer_c_avx.c', 'w') as f:
    f.write(c_code_avx)

import os
os.system('gcc -O3 -march=native -shared -fPIC -o /app/outer_c_avx.so /app/outer_c_avx.c')

lib_avx = ctypes.CDLL('/app/outer_c_avx.so')
lib_avx.outer_product_avx.restype = None
lib_avx.outer_product_avx.argtypes = [
    ctypes.POINTER(ctypes.c_double),
    ctypes.POINTER(ctypes.c_double),
    ctypes.POINTER(ctypes.c_double),
    ctypes.c_int,
    ctypes.c_int
]

lib = ctypes.CDLL('/app/outer_c.so')

for n in [10, 100, 1000, 5000, 10000]:
    v1 = np.ascontiguousarray(np.random.randn(n), dtype=np.float64)
    v2 = np.ascontiguousarray(np.random.randn(n), dtype=np.float64)

    # np.outer
    reps = 10 if n < 5000 else 5
    t0 = time.time()
    for _ in range(reps):
        r1 = np.outer(v1, v2)
    t_outer = (time.time() - t0) / reps

    # C plain
    result = np.empty((n, n), dtype=np.float64)
    v1_ptr = v1.ctypes.data_as(ctypes.POINTER(ctypes.c_double))
    v2_ptr = v2.ctypes.data_as(ctypes.POINTER(ctypes.c_double))
    result_ptr = result.ctypes.data_as(ctypes.POINTER(ctypes.c_double))

    t0 = time.time()
    for _ in range(reps):
        lib.outer_product(v1_ptr, v2_ptr, result_ptr, n, n)
    t_c = (time.time() - t0) / reps

    # C AVX
    result2 = np.empty((n, n), dtype=np.float64)
    result2_ptr = result2.ctypes.data_as(ctypes.POINTER(ctypes.c_double))

    t0 = time.time()
    for _ in range(reps):
        lib_avx.outer_product_avx(v1_ptr, v2_ptr, result2_ptr, n, n)
    t_avx = (time.time() - t0) / reps

    print(f'n={n}: np.outer={t_outer:.6f}, C={t_c:.6f}, AVX={t_avx:.6f}, match_avx={np.allclose(r1, result2)}')
